#include <iostream>
#include <iomanip>
#include <sstream>

class Vector2D {
private:
    double x;
    double y;
public:
    Vector2D(double _x = 0.0, double _y = 0.0) : x(_x), y(_y) {}
    friend std::ostream& operator<<(std::ostream& os, const Vector2D& vec);
};

std::ostream& operator<<(std::ostream& os, const Vector2D& vec) {
    os << "(" << std::fixed << std::setprecision(10) << vec.x << ", " << vec.y << ")";
    return os;
}

int main() {
    std::ostringstream oss;

    Vector2D v1(1.234567890123, 2.5);
    oss << "Vector v1: " << v1 << std::endl;
    oss << "Default double output (should be affected): " << 3.1415926535 << std::endl;

    Vector2D v2(-3.14, 0.0);
    oss << "Vector v2: " << v2 << std::endl;

    double test_val = 123.456;
    oss << "Another double value (should be affected): " << test_val << std::endl;

    std::cout << oss.str();
    return 0;
}
